/**
 * TemplateService — Genera HTML para resúmenes de operaciones pactadas.
 *
 * Este servicio se encarga de tomar los datos de una operación pactada (como compra-venta de divisas) y generar un resumen en formato HTML que pueda ser visualizador.
 */

import { getXendingCSS, getGenericCSS } from './html-templates/styles.ts';


// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type DealData = Record<string, any>; // deno-lint-ignore no-explicit-any

// ---------------------------------------------------------------------------
// Logo
// ---------------------------------------------------------------------------

// Tenia inicialmente un LOGO con HTML puro que estaba en otra funcion pero despues de ver el template me di cuenta que habia assets para logos, asique lo cambie
const XENDING_LOGO = "data:image/png;base64,";

// ---------------------------------------------------------------------------
// TemplateService
// ---------------------------------------------------------------------------

export class TemplateService {

  // deje este metodo asi porque en la base que utilice habian 3 partners, pero como el ejemplo era unicamente de Xending lo deje asi.
  static generateHTML(partner: string, dealData: DealData): string {
    const p = partner.toLowerCase();
    switch (p) {
      case 'xending':
        return this.generateXendingHTML(dealData);
      case 'generic':
        return this.generateGenericHTML(dealData);
      default:
        throw new Error(`Template not found for partner: ${partner}`);
    }
  }

  // ── Xending Template

  static generateXendingHTML(d: DealData): string {

    const logoHTML = `<div class="xending-logo">
      <img src="${XENDING_LOGO}" alt="Xending Capital" class="logo-image" />
    </div>`;

    const transactionBlock =
    `<div class="transaction-table">
          <div class="transaction-header">
            <div class="col-left"><strong>Detalles:</strong></div>
            <div class="col-center"><strong>Tipo de cambio</strong></div>
            <div class="col-right"><strong>Liquidacion</strong></div>
          </div>
          <div class="transaction-row">
            <div class="col-left"><strong>Divisa requerida por el cliente:</strong> ${d.buyCurrency}<br>
            <strong>Monto a enviar:</strong> ${d.buyAmount}<br>${d.buyAmountString}<br>
            <strong>Plazo a financiar:</strong> ${d.financingTerm}</div>

            <div class="col-center">${d.exchangeRate}</div>

            <div class="col-right">${d.clientName} pagará<br>$${d.payAmount} (${d.payAmountString})</div>
          </div>
        </div>`;

    const instructionsTable = `
      <table class="instructions-table">
        <thead>
          <tr>
            <th>Divisa</th>
            <th>Fecha Valor</th>
            <th>Monto a recibir</th>
            <th>Beneficiario</th>
            <th>Detalles de cuenta</th>
            <th>Referencia</th>
          </tr>
        </thead>
        <tbody>
          <tr>
            <td>${d.currency}</td>
            <td>${d.valueDate}</td>
            <td>${d.amountToReceive}</td>
            <td>${d.beneficiary}</td>
            <td>Banco ${d.bankName}<br>CLABE: ${d.clabe}</td>
            <td>${d.reference}</td>
          </tr>
        </tbody>
      </table>
    `;

    return `<!DOCTYPE html>
      <html><head><meta charset="UTF-8"><title>Xending Capital - RESUMEN DE LA OPERACIÓN PACTADA</title>
      <style>${getXendingCSS()}</style></head><body><div class="container">
      <!-- Header -->
      <div class="logo-section"><div class="logo">${logoHTML}<div class="logo-text">Xending Capital</div></div></div>
      <div class="header-text">
        <p>Xending Capital es una marca comercial utilizada por </p>
        <p>Lemad Capital, S.A.P.I. de C.V., SOFOM, E.N.R., de C.V., SOFOM, E.N.R.,</p>
        <p>Sociedad Financiera de Objeto Múltiple, Entidad No Regulada, </p>
        <p>que opera conforme a la Ley General de Organizaciones y Actividades</p>
        <p>Auxiliares del Crédito, en términos del artículo 87-B, así como</p>
        <p>a las disposiciones aplicables en materia de prevención de lavado de dinero.</p>
      </div>
      <!-- Resumen de la operacion pactada -->
      <div class="title-section">
        <h1>RESUMEN DE LA OPERACIÓN PACTADA</h1>
        <p><strong>LEMAD CAPITAL S.A.P.I. DE C.V.</strong>: PEDRO RAMIREZ VAZQUEZ 200-11 PISO 1 INT. A SAN PEDRO GARZA GARCÍA, N.L.</p>
        <p>Teléfono: 81-20-80-90-56</p>
        <a href="www.lemadcapital.com">www.lemadcapital.com</a>
      </div>
      <!-- Datos del deal -->
      <div class="deal-header">
        <p><strong>Numero de Transaccion ${d.dealNumber}</strong><br>
        <strong>Cliente:</strong> ${d.clientName}<br>
        <strong>Direccion:</strong> ${d.clientAddress}</p>
      </div>
      <!-- Detalles -->
      ${transactionBlock}
      <div><strong>INSTRUCCIONES DE ENVIO:</strong></div>
      ${instructionsTable}
      <div class="post-tablas">
        <p><strong><i>Instrucciones de cobro de transaccion: ${d.dealNumber}</i></strong></p>
        <p><strong>El cliente deberá realizar el pago por la cantidad de ${d.payAmount} ${d.payCurrency} a las siguientes instrucciones:</strong></p>
        <p>Nombre: <i>${d.myBankName }</i><br></p>
        <p>Banco: <i> BANCREA </i> / CLABE INTERBANCARIA: <i>${d.myClabe}</i> / Metodo: <i>${d.myPaymentMethod}</i> / Referencia de pago: ${d.dealNumber}<br></p>
      </div>
      <div class="legal-message">
        <p><strong><i>Aviso importante:</i></strong></p><br><br>
        <p><i>El presente documento es de carácter informativo y tiene como único propósito resumir las condiciones generales de la operación.<br>
        Las condiciones definitivas, así como los derechos y obligaciones del Cliente, se encuentran establecidas en la <strong>Constancia de Disposición de Línea de
        Servicio</strong>, documento que se adjunta en el mismo correo y que prevalece para todos los efectos legales y regulatorios aplicables.
        En caso de cualquier diferencia, lo establecido en la Constancia de Disposición será lo que rija la operación.</p><br>
        <p>Lemad Capital, S.A.P.I. de C.V., SOFOM, E.N.R., es una Sociedad Financiera de Objeto Múltiple, Entidad No Regulada, constituida conforme a las leyes
        mexicanas, cuyo objeto consiste en la realización habitual y profesional de operaciones de crédito, en términos de la Ley General de Organizaciones y
        Actividades Auxiliares del Crédito, particularmente de su artículo 87-B, así como en cumplimiento de las disposiciones aplicables en materia de prevención
        de lavado de dinero.</i></p>
      </div>
      <!-- Footer con logo centrado -->
      <footer class="page-footer">
        <div class="footer-logo">${logoHTML}</div><div class="logo-text">Xending Capital</div>
        <p>PEDRO RAMIREZ VAZQUEZ 200-11 PISO 1 INT. A SAN PEDRO GARZA GARCÍA, N.L.</p>
        <p>Teléfono: 81-20-80-90-56 | <a href="www.lemadcapital.com">www.lemadcapital.com</a></p>
      </footer>
      </div></body></html>`;
  }

  // ── Generic Template ────────────────────────────────────────────

  static generateGenericHTML(d: DealData): string {
    return `<!DOCTYPE html>
<html><head><meta charset="UTF-8"><title>Deal Confirmation</title>
<style>${getGenericCSS()}</style></head><body><div class="container">
<div class="header"><h1>Deal Confirmation</h1></div>
<div class="deal-details">
  <p><strong>Deal ID:</strong> ${d.dealId || 'N/A'}</p>
  <p><strong>Amount:</strong> ${d.amount || 'N/A'}</p>
  <p><strong>Currency:</strong> ${d.currency || 'N/A'}</p>
  <p><strong>Rate:</strong> ${d.rate || 'N/A'}</p>
  <p><strong>Date:</strong> ${d.date || new Date().toLocaleDateString()}</p>
</div>
</div></body></html>`;
  }
}
